        "descriptionModule": {
          "briefSummary": "We are examining the role of maternal bone lead turnover during pregnancy and lactation as a potential source of lead exposure for the fetus and the infant (via breast milk). A cohort, ascertained at entry to care, consists of \\>1000 women to be followed through pregnancy. In the postpartum subjects are recruited for a nested case control study to assess the influence of lactation on maternal bone density, maternal blood lead and breast milk lead."
        },
        "conditionsModule": {
          "conditions": [
            "Lead Poisoning"
          ],
          "keywords": [
            "Pregnancy",
            "Lead Exposure",
            "Lactation",
            "Bone Mineralization",
            "Maternal-Fetal Exchange"
          ]
        },
        "designModule": {
          "studyType": "OBSERVATIONAL",
          "designInfo": {
            "observationalModel": "NATURAL_HISTORY",
            "timePerspective": "PROSPECTIVE"
          },
          "enrollmentInfo": {
            "count": 1000
          }
        },
        "eligibilityModule": {
          "eligibilityCriteria": "1. Positive pregnancy test, age 12-35 and informed consent;\n2. Gestation \\<28 weeks at entry to prenatal care;\n3. No history of serious chronic or metabolic diseases, which could affect maternal growth or bone density;\n4. Not corticosteroid user or diagnosed use of illicit drugs;\n5. Eligible for lactation study: Ascertainment during or participation in the pregnancy study and a negative pregnancy test.",
          "healthyVolunteers": true,
          "sex": "FEMALE",
