        "outcomeMeasuresModule": {
          "outcomeMeasures": [
            {
              "type": "PRIMARY",
              "title": "Matched Related Transplants Who Develop Grade II-IV Acute Graft Versus Host Disease (GVHD).",
              "description": "The number of subjects in the matched sibling cohort who develop grades II-IV acute GVHD will be assessed by consensus criteria and graded on Bone Marrow Transplant Clinical Trials Network Manual of Procedures suggested grading sheets. Grade I is mild GVHD involving up to 25% of the subject's skin; Grade II is moderate GVHD. involving 25 to 50% of the subject's skin and can include mild changes in liver and/or mild diarrhea; Grade III is severe GVHD involving over 50% of the subject's skin. Liver involvement is likely as are stomach cramps and diarrhea; and Grade 4 is very severe GvHD. Skin may be blistered and may have broken down in places. Skin may be yellow due to liver injury. Severe diarrhea is common. Subjects in the matched unrelated donors are not included in this analysis.",
              "reportingStatus": "POSTED",
              "paramType": "COUNT_OF_PARTICIPANTS",
              "unitOfMeasure": "Participants",
              "timeFrame": "Day 100",
              "groups": [
