        "outcomesModule": {
          "primaryOutcomes": [
            {
              "measure": "Change in Behaviorally Coded Challenging Behaviors (Agitated, Disruptive, Resistive)",
              "description": "Behavioral coding of videos for agitated, disruptive, or resistive behaviors will be used to identity changes in behavior before and after the intervention.",
              "timeFrame": "3 months"
            },
            {
              "measure": "Change in Caregiver Stress - Reaction to Memory Symptoms (Bother)",
              "description": "Caregiver reaction to behavioral symptoms of the Person with Dementia (PWD) was measured by the Revised Memory and Problem Behavior Checklist (RMPBC). The RMPBC contains 24 items, each with two parts. Each item represents a behavior; if the behavior has been exhibited by the PWD in the past week, the caregiver reports the behavior as present. If the behavior is present, the caregiver then reports \"how much it bothered you?\" on a five-point Likert scale (0 = not at all; 4 = extremely). If the behavior was not present, no \"bother\" score is provided, and the item is scored 0. The items are summed for a total score (range = 0-96) and for three subscales representing bother due to memory-related problems (range = 0-28), depressive symptoms (range = 0-36), and disruptive symptoms (range = 0-32). A higher score indicates a greater negative reaction to behaviors.",
              "timeFrame": "Baseline, 1 month, 3 months"
            },
            {
              "measure": "Change in Caregiver Stress - Reaction to Depressive Symptoms (Bother)",
              "description": "Caregiver reaction to behavioral symptoms of the person with dementia (PWD) was measured by the Revised Memory and Problem Behavior Checklist (RMPBC). The RMPBC contains 24 items, each with two parts. Each item represents a behavior; if the behavior has been exhibited by the PWD in the past week, the caregiver reports the behavior as present. If the behavior is present, the caregiver then reports \"how much it bothered you?\" on a five-point Likert scale (0 = not at all; 4 = extremely). If the behavior was not present, no \"bother\" score is provided, and the item is scored 0. The items are summed for a total score (range = 0-96) and for three subscales representing bother due to memory-related problems (range = 0-28), depressive symptoms (range = 0-36), and disruptive symptoms (range = 0-32). A higher score indicates a greater negative reaction to behaviors.",
              "timeFrame": "Baseline, 1 month, 3 months"
            },
            {
              "measure": "Change in Caregiver Stress - Desire to Instituionalize",
              "description": "Desire to institutionalize was measured using a modified Desire to Institutionalize Scale. The modified Desire to Institutionalize Scale contains six items rated as dichotomous yes or no (1 = yes; 0 = no). A higher score indicates a greater desire to institutionalize (range = 0-6). Internal consistency for the Desire to Institutionalize scale is adequate (α = .69-.77) and has shown adequate construct validity through factor analysis.",
              "timeFrame": "Baseline, 1 month, 3 months"
            },
            {
              "measure": "Change in Caregiver Stress - Biological Sensor Data",
              "description": "Biological stress reactions measured by sensor",
              "timeFrame": "Baseline, 1 month, 3 months"
            },
            {
              "measure": "Change in Caregiver Burden",
              "description": "Caregiver burden was measured using the Modified Zarit Burden Scale that contains 12 items with a 5-point Likert scale (0 = never; 4 = nearly always) adapted from the 22-item Zarit Burden Interview. A higher score indicates greater caregiver burden (range = 0-48). The Modified Zarit Burden Scale has shown adequate internal consistency (α = .88) and excellent concurrent validity (r = .92- .97) with the full Zarit Burden Interview.",
              "timeFrame": "Baseline, 1 month, 3 months"
            },
            {
              "measure": "Change in Caregiver Health and Wellbeing - Depression",
              "description": "Caregiver depression was measured using the Center for Epidemiologic Studies Depression scale (CES-D). The CES-D contains 20 items with a 4-point Likert scale ranging from 0 = rarely or none of the time (i.e., less than 1 day in past week) to 3 = most or all of the time (i.e., 5-7 days in past week). A higher score indicates greater depression (range = 0-60). The CES-D shows adequate internal consistency (α = .84-.90), moderate convergent validity with other depression scales (r = .44-.75), and has been shown to effectively measure change in psychoeducational interventions for dementia caregivers.",
              "timeFrame": "Baseline, 1 month, 3 months"
            },
            {
              "measure": "Change in Caregiver Health and Wellbeing - Competence",
              "description": "Caregiver sense of competence was measured using the Short Sense of Competence Questionnaire (SSCQ).37 The SSCQ contains seven negatively worded items (e.g., \"I feel strained in my interaction with...\"). Each item is rated on a five-point Likert scale and dichotomized to agree (i.e., agree very strongly, agree, neutral) or disagree (i.e., disagree or strongly disagree). The items where the caregiver disagreed are summed for the total score. A higher score indicates a higher sense of competence (range = 0-7). The SSCQ shows adequate internal consistency (α = .76) and concurrent validity with the original Sense of Competence Questionnaire (r = .88).",
              "timeFrame": "Baseline, 1 month, 3 months"
            },
            {
              "measure": "Change in Caregiver Health and Wellbeing - Sleep Disturbance",
              "description": "Caregiver sleep disturbance was measured by the Pittsburgh Sleep Quality Index (PSQI). The PSQI contains 19 items with a 4-point Likert scale across seven domains: sleep quality, sleep latency, sleep duration, habitual sleep ef- ficiency, sleep disturbances, use of sleeping medications, and daytime dysfunction. A higher global score indicates worse sleep quality (range = 0-21). The PSQI shows adequate internal consistency (α = .83) and adequate validity in differentiating patients with and without sleep disorders.",
              "timeFrame": "Baseline, 1 month, 3 months"
            },
            {
              "measure": "Change in Caregiver Health and Wellbeing - Medication Use",
              "description": "Caregivers taking PRN anxiolytics, hypnotics, or antipsychotic medication.",
              "timeFrame": "Baseline, 1 month, 3 months"
            },
            {
              "measure": "Change in Caregiver Health and Wellbeing - Confidence in Managing BPSD",
              "description": "Caregivers reported their three priority care challenges at baseline using the Caregiver Target Problems Questionnaire (Teri, McCurry, Logsdon, \\& Gibbons, 2005). The Caregiver Target Problems Questionnaire was adapted and used to identify caregiver priority care challenges for frequency, severity, and confidence at baseline and 3-months (Teri et al., 2005). Prior to group allocation, caregivers identified three priority care challenges and rated them on 5-point Likert scales: frequency of the challenge (0 = None to 4 = Daily or more often), severity of the challenge (0 = Trivial to 4 = Severe), and confidence in managing the challenge (0 = Unable to manage to 4 = Very confident). At the end of the 3-month trial, caregivers repeated their ratings of the baseline care challenges. Improvement was indicated increase in confidence from baseline to 3-months.",
              "timeFrame": "Baseline, 3 months"
            },
