      "resultsSection": {
        "participantFlowModule": {
          "preAssignmentDetails": "Caregiver-Person with Dementia (PWD) dyads were randomly assigned to the intervention (FamTechCare) group or the attention control group using a quarter-based blocking strategy with 1:1 allocation developed by the study statistician. Caregivers in multiple dyad homes were cluster randomized to the same group.",
          "recruitmentDetails": "Site A participants were recruited by advertisements in local media, university email, and regional conferences for caregivers. Site B participants were primarily recruited through an Alzheimer Disease center, a memory care clinic, and community outreach activities.",
          "groups": [
