        "armsInterventionsModule": {
          "armGroups": [
            {
              "label": "Tailored Activity Program",
              "type": "EXPERIMENTAL",
              "description": "The Tailored Activity Program unfolds over 3 phases: Phase I (sessions 1-2) involves assessment of Person with Dementia (PwD)capacity and interests, caregiver (CG) interactions and the physical environment and CG education. Phase II (sessions 3-6) involves identifying and implementing 3 \"Activity Prescriptions\" tailored to PwD's cognitive and interest profile using an algorithmic guide. The prescription summarizes PwD capabilities in lay language, identifies the activity and a specific activity goal, and provides specific instructions for introducing the activity. CGs are trained to integrate activities in daily care. Also provided are simple deep breathing stress reduction techniques to address CG upset. Phase III (sessions 7-8) involves instructing CGs in simplifying activities for future cognitive declines and applying simplification principles to other care challenges.",
              "interventionNames": [
                "Behavioral: Tailored Activity Program"
              ]
            },
            {
              "label": "Home Safety and Education Program",
              "type": "ACTIVE_COMPARATOR",
              "description": "This arm receives 6 in-home and 2 brief telephone education sessions. Each contact is structured to provide helpful education. Sessions include information on home safety, fall risk assessment, talking to your doctor, advanced planning, identifying resources, and caring for the caregiver (CG). Each session is prescriptive and designed to maximize attention; yet, sessions will not involve any component of the intervention group. To engage the person with dementia (PwD), the interventionist will socially engage the person briefly in select sessions. Time spent with CG and PwD in the control group is comparable to that for intervention dyads.",
              "interventionNames": [
                "Other: Home Safety and Education Program"
              ]
            }
          ],
          "interventions": [
            {
              "type": "BEHAVIORAL",
              "name": "Tailored Activity Program",
              "description": "TAP is designed to tap into spared or residual abilities and provide an environment supportive of these abilities. Activities are selected that build on preserved capabilities, long-term interests and procedural memory, but which do not tax areas of cognition that are most impaired (e.g., memory, new learning). Activities selected are simplified (1 to 2 vs multiple, complex steps), thereby minimizing errors. The activity environment is set up to provide auditory or tactile cues to facilitate recall and guide initiation and sequencing. By grading activities to match PwD capabilities, the interventionist minimizes demand that may heighten stress (e.g., high functioning individuals are introduced to more goal-directed, multi-step activities, whereas lower functioning individuals are introduced to activities involving repetitive motion (e.g., washing windows, folding towels, placing materials in a bin) and integrate multi-sensory stimulation (e.g., soft music, objects pleasant to touch).",
              "armGroupLabels": [
                "Tailored Activity Program"
              ],
              "otherNames": [
                "TAP",
                "CAP"
              ]
            },
            {
              "type": "OTHER",
              "name": "Home Safety and Education Program",
              "description": "The control group intervention is designed to control for the nonspecific elements of TAP such as social engagement with PwD and CG which may affect outcomes. It is a fully-structured, nondirective, supportive education approach that conveys empathy, respect and specific disease education elements of which have been tested in other trials. Unlike TAP, this group contains no active elements beyond its nonspecific components, has no long-lasting treatment effects, and no theoretical basis to support an effect on agitation. It is delivered by a trained research team member who uses active listening, open questioning, reflecting back, and summation with CGs.",
              "armGroupLabels": [
                "Home Safety and Education Program"
              ]
            }
          ]
        },
