        "armsInterventionsModule": {
          "armGroups": [
            {
              "label": "Online psychoeducation",
              "type": "EXPERIMENTAL",
              "description": "The online psychoeducation was presented virtually via Zoom videoconferencing for synchronous group meeting. It has two core components: didactic teaching and active participation. The didactic teaching provided information support about dementia caregiving which was delivered via Powerpoint presentations. The programme allowed: (1) hands-on skill training opportunities to rehearse caregiving skills through simulation and written assignments; (2) sharing of caregiving experiences and learning vicariously from other participants through group discussion; (3) reflection on own caregiving approach; and (4) addressing negative emotions through practicing relaxation technique. Participants went through six-weekly psychoeducation sessions in a small group of five to eight. Each psychoeducation session consisted of didactic teaching and active participation which lasted for 120 minutes. Participants went through discussion, simulation and was given home assignment weekly.",
              "interventionNames": [
                "Behavioral: Online psychoeducation"
              ]
            },
            {
              "label": "Face-to-face psychoeducation",
              "type": "ACTIVE_COMPARATOR",
              "description": "Face-to-face psychoeducation had the same content and flow of presentation as online psychoeducation. The only difference was the mode of delivery which was presented physically in the community center.",
