        },
        "oversightModule": {
          "oversightHasDmc": false,
          "isFdaRegulatedDrug": false,
          "isFdaRegulatedDevice": false
        },
        "descriptionModule": {
          "briefSummary": "After a one-year phase of development, primary nursing (process-responsible nursing; PP) has been practically implemented on a pilot ICU since January 2022 at the Heart and Diabetes Center NRW. PP plan, coordinate and evaluate the nursing carried out. In the further course, an examination between the project ICU and another ICU without PP with a focus on thoracic and cardiovascular surgery (surgical ICU) is to be carried out.\n\nThe primary goal of this pilot study is to test the feasibility of a large-scale RCT with patient-related outcomes.",
          "detailedDescription": "After a one-year phase of development, primary nursing (process-responsible nursing; PP) has been practically implemented on a pilot ICU since January 2022 at the Heart and Diabetes Center NRW.\n\nPreviously, the system of room care (standard care) was carried out. PP plan, coordinate and evaluate the nursing carried out. In addition, they take on the care responsibility for a maximum of two patients and also carry out the care at the same time. In the further course, an examination between the project ICU and another ICU with a focus on thoracic and cardiovascular surgery (surgical ICU) is to be carried out.\n\nThe primary goal of this pilot study is to test the feasibility of a large-scale RCT. For this purpose, the duration of delirium after the introduction of a PP on the project ICU should be compared with the previous care organization as standard care in a surgical ICU. Secondary goals e.g. include: the incidence of delirium, anxiety, as well as the satisfaction of the relatives and the effects of PP on nurses are shown."
        },
        "conditionsModule": {
          "conditions": [
            "Nurse's Role"
          ],
          "keywords": [
            "delirium",
            "intensive care units",
            "primary nursing",
            "professional practice"
          ]
        },
        "designModule": {
          "studyType": "INTERVENTIONAL",
          "phases": [
            "NA"
          ],
          "designInfo": {
            "allocation": "RANDOMIZED",
            "interventionModel": "PARALLEL",
            "interventionModelDescription": "RCT",
            "primaryPurpose": "SUPPORTIVE_CARE",
            "maskingInfo": {
              "masking": "NONE"
            }
          },
          "enrollmentInfo": {
            "count": 94,
            "type": "ACTUAL"
          }
        },
        "armsInterventionsModule": {
          "armGroups": [
            {
              "label": "primary nursing",
              "type": "EXPERIMENTAL",
              "description": "The intervention group with patients who are cared with primary nursing (process-responsible nursing; PP) after elective thoracic and/or cardiovascular surgery are on the intervention ICU. Patients are assigned to the intervention group if they stay for at least 3 days on the ICU. PP take on\n\n* the responsibility of the nursing process\n* the daily care according to the individual patient case\n* direct communication with all professional groups involved in care\n* responsibility for the quality of care of the assigned patients over a fixed period of at least 14 and a maximum of 50 days - after that the primary nurse will change.\n\nIn this way, PP also take on the nursing anamnesis as well as the planning, implementation and evaluation of the nursing care. The nursing care ratio is at least 1:2",
              "interventionNames": [
                "Other: primary nursing"
              ]
            },
            {
              "label": "standard care",
              "type": "NO_INTERVENTION",
              "description": "The control group with patients who are cared for according to the principle of standard care (area care or room care) is located on another ICU. There is no PP responsible for the target group and the allocation of nursing staff to patients is redefined at the start of each shift. The nursing care ratio is at least 1:2."
            }
          ],
          "interventions": [
            {
              "type": "OTHER",
              "name": "primary nursing",
              "description": "The primary responsibility of one nurse for the planning, evaluation, and care of a patient throughout the course of illness, convalescence, and recovery.",
              "armGroupLabels": [
                "primary nursing"
              ],
              "otherNames": [
                "process-responsible nursing (PP)"
              ]
            }
          ]
        },
        "outcomesModule": {
          "primaryOutcomes": [
            {
              "measure": "duration of delirium",
              "description": "As a syndrome, delirium represents a serious brain-organic emergency situation with dangerous consequences. The incidence of delirium in cardiac surgery ranges from \\<10% to \\>25%. Data collection: Confusion Assessment Method for Intensive Care Unit (CAM-ICU).",
              "timeFrame": "3 times per day over one year."
            }
          ],
          "secondaryOutcomes": [
            {
              "measure": "incidence of delirium",
              "description": "As a syndrome, delirium represents a serious brain-organic emergency situation with dangerous consequences. The incidence of delirium in cardiac surgery ranges from \\<10% to \\>25%. Data collection: Confusion Assessment Method for Intensive Care Unit (CAM-ICU).",
              "timeFrame": "3 times per day over one year."
            },
            {
              "measure": "pain (incidence and strength of pain)",
              "description": "An unpleasant sensation induced by noxious stimuli which are detected by nerve endings. Data collection: Numeric Rating Scale (NRS) or Critical Care Pain Observation Tool (CPOT).",
              "timeFrame": "3 times per day over one year."
            },
            {
              "measure": "incidence and risk of decubitus",
              "description": "An ulceration caused by prolonged pressure on the skin and tissues when one stays in one position for a long period of time, such as lying in bed. Data collection: Braden-Scale and documentation.",
              "timeFrame": "Once per day over one year."
            },
            {
              "measure": "anxiety",
              "description": "Feelings or emotions of dread, apprehension, and impending disaster but not disabling as with anxiety disorders. Data collection: Numeric Rating Scale (NRS).",
              "timeFrame": "3 times per day over one year."
            },
            {
              "measure": "need of care (Barthel-Index)",
              "description": "Need of care describes, how much time and extend of care a patient needs. Data-Collection: Barthel-Index.",
              "timeFrame": "Once per week over one year."
            },
            {
              "measure": "satisfaction of the relatives",
              "description": "Satisfaction of relatives means the satisfaction with care of the relatives' patients trough nurses. Data collection: Data collection: standardized questionaire.",
              "timeFrame": "Once during ICU-care over one year."
            },
            {
              "measure": "effects of PP on nurses (only intervention group)",
              "description": "Effects of PP on nurses means the effects of the new organizational system of nursing care on nurses. Data collection: focus group interview with nurses.",
              "timeFrame": "Once during the study in one year."
            }
          ]
        },
        "eligibilityModule": {
          "eligibilityCriteria": "Inclusion Criteria:\n\n* All patients are included who are at least 65 years old,\n* understand German language,\n* whose health insurance company has concluded a quality contract with the Heart and Diabetes Center NRW (HDZ NRW),\n* Elective thoracic and cardiovascular surgery,\n* Intensive care for at least three days on ICU.\n\nRelatives:\n\n* at least 18 years old,\n* patients have to receive PP.\n\nFocus group interview with nurses of the intervention-ICU:\n\n* Nurses have to be at least 18 years old,\n* Nurses belong the the intervention-ICU.\n\nExclusion Criteria:\n\nPatients who\n\n* are \\< 65 years old,\n* whose health insurance company has not concluded a quality contract with the HDZ NRW,\n* cannot be admitted due to allocation by randomization and a lack of free bed on the destination ICU,\n* have not given their informed consent,\n* cannot participate in the CAM-ICU screening due to neurological diseases,\n* in whom the screening using CAM-ICU could not be carried out over the entire intensive care stay and/or\n* belong to the target group but stay less than three days after their elective operation in the ICU.\n\nRelatives:\n\n* not at least 18 years old and/or\n* the patients do not receive PP.\n\nFocus group interview with nurses of the intervention-ICU:\n\n* Nurses who are not at least 18 years old and\n* Nurses do not belong to the intervention-ICU.",
          "healthyVolunteers": true,
          "sex": "ALL",
